import java.util.*;
import java.io.*;

class Main {
    public static int solution(String[] strs) {
        int maxLen = -1;

        for (int i = 0; i < strs.length; i++) {
            List<String> subsequences = generateSubsequences(strs[i]);
            for (String subseq : subsequences) {
                boolean isUncommon = true;
                for (int j = 0; j < strs.length; j++) {
                    if (i != j && isSubsequence(subseq, strs[j])) {
                        isUncommon = false;
                        break;
                    }
                }
                if (isUncommon) {
                    maxLen = Math.max(maxLen, subseq.length());
                }
            }
        }

        return maxLen;
    }

    private static boolean isSubsequence(String s, String t) {
        int i = 0;
        for (char c : t.toCharArray()) {
            if (i < s.length() && s.charAt(i) == c) {
                i++;
            }
        }
        return i == s.length();
    }

    private static List<String> generateSubsequences(String s) {
        List<String> result = new ArrayList<>();
        int n = s.length();
        for (int mask = 0; mask < (1 << n); mask++) {
            StringBuilder subseq = new StringBuilder();
            for (int i = 0; i < n; i++) {
                if ((mask & (1 << i)) != 0) {
                    subseq.append(s.charAt(i));
                }
            }
            result.add(subseq.toString());
        }
        return result;
    }

    public static void main(String[] args) throws Exception {
        BufferedReader br = new BufferedReader(new InputStreamReader(System.in));
        String line = br.readLine().trim();

        // Parse JSON array format
        line = line.substring(1, line.length()-1); // Remove [ ]
        List<String> strList = new ArrayList<>();

        if (line.length() > 0) {
            String[] parts = line.split(",");
            for (String part : parts) {
                part = part.trim();
                if (part.startsWith("\"") && part.endsWith("\"")) {
                    strList.add(part.substring(1, part.length()-1));
                }
            }
        }

        String[] strs = strList.toArray(new String[0]);
        int result = solution(strs);
        System.out.println(result);
    }
}

