struct ListNode* arrayToList(int* arr, int size);
void printList(struct ListNode* head);

struct ListNode* solution(struct ListNode* l1, struct ListNode* l2) {
    long long num1 = listToNum(l1);
    long long num2 = listToNum(l2);
    long long total = num1 + num2;
    return numToList(total);
}

long long listToNum(struct ListNode* head) {
    long long num = 0;
    long long multiplier = 1;
    while (head) {
        num += head->val * multiplier;
        multiplier *= 10;
        head = head->next;
    }
    return num;
}

struct ListNode* numToList(long long num) {
    if (num == 0) {
        struct ListNode* node = (struct ListNode*)malloc(sizeof(struct ListNode));
        node->val = 0;
        node->next = NULL;
        return node;
    }

    struct ListNode* dummy = (struct ListNode*)malloc(sizeof(struct ListNode));
    struct ListNode* current = dummy;
    while (num > 0) {
        int digit = num % 10;
        current->next = (struct ListNode*)malloc(sizeof(struct ListNode));
        current->next->val = digit;
        current->next->next = NULL;
        current = current->next;
        num /= 10;
    }
    return dummy->next;
}

struct ListNode* arrayToList(int* arr, int size) {
    if (size == 0) return NULL;
    struct ListNode* head = (struct ListNode*)malloc(sizeof(struct ListNode));
    head->val = arr[0];
    head->next = NULL;
    struct ListNode* current = head;
    for (int i = 1; i < size; i++) {
        current->next = (struct ListNode*)malloc(sizeof(struct ListNode));
        current->next->val = arr[i];
        current->next->next = NULL;
        current = current->next;
    }
    return head;
}

