import json
import sys

class Robot:
    def __init__(self, width, height):
        self.width = width
        self.height = height
        self.x = 0
        self.y = 0
        self.direction = 0  # 0=East, 1=North, 2=West, 3=South
        self.dirs = ['East', 'North', 'West', 'South']
        self.dx = [1, 0, -1, 0]
        self.dy = [0, 1, 0, -1]

    def step(self, num):
        for _ in range(num):
            next_x = self.x + self.dx[self.direction]
            next_y = self.y + self.dy[self.direction]

            if 0 <= next_x < self.width and 0 <= next_y < self.height:
                self.x = next_x
                self.y = next_y
            else:
                self.direction = (self.direction + 1) % 4
                next_x = self.x + self.dx[self.direction]
                next_y = self.y + self.dy[self.direction]
                if 0 <= next_x < self.width and 0 <= next_y < self.height:
                    self.x = next_x
                    self.y = next_y

    def getPos(self):
        return [self.x, self.y]

    def getDir(self):
        return self.dirs[self.direction]

def solution(operations):
    robot = None
    results = []

    for op in operations:
        if op[0] == 'Robot':
            robot = Robot(op[1], op[2])
            results.append(None)
        elif op[0] == 'step':
            robot.step(op[1])
            results.append(None)
        elif op[0] == 'getPos':
            results.append(robot.getPos())
        elif op[0] == 'getDir':
            results.append(robot.getDir())

    return results

