    for (int i = 0; i < n; i++) {
        for (int j = i + 1; j < n; j++) {
            int diffCount = 0;
            for (int k = 0; k < dict[i].length(); k++) {
                if (dict[i][k] != dict[j][k]) {
                    diffCount++;
                    if (diffCount > 1) break;
                }
            }
            if (diffCount == 1) return true;
