import java.util.*;
import java.io.*;

class Main {
    public static boolean solution(int[][] blocked, int[] source, int[] target) {
        if (blocked.length == 0) return true;

        int maxArea = blocked.length * (blocked.length - 1) / 2;
        Set<String> blockedSet = new HashSet<>();
        for (int[] b : blocked) {
            blockedSet.add(b[0] + "," + b[1]);
        }

        return bfs(source, target, blockedSet, maxArea) && bfs(target, source, blockedSet, maxArea);
    }

    private static boolean bfs(int[] start, int[] end, Set<String> blocked, int maxArea) {
        String startKey = start[0] + "," + start[1];
        if (blocked.contains(startKey)) return false;

        Queue<int[]> queue = new LinkedList<>();
        Set<String> visited = new HashSet<>();
        int[][] directions = {{0, 1}, {1, 0}, {0, -1}, {-1, 0}};

        queue.offer(start);
        visited.add(startKey);

        while (!queue.isEmpty() && visited.size() <= maxArea) {
            int[] curr = queue.poll();
            if (curr[0] == end[0] && curr[1] == end[1]) return true;

            for (int[] dir : directions) {
                int nx = curr[0] + dir[0];
                int ny = curr[1] + dir[1];
                String key = nx + "," + ny;

                if (nx >= 0 && nx < 1000000 && ny >= 0 && ny < 1000000) {
                    if (!blocked.contains(key) && !visited.contains(key)) {
