                        queue.offer(new int[]{nx, ny});
                    }
                }
            }
        }

        return visited.size() > maxArea;
    }

    public static void main(String[] args) throws Exception {
        BufferedReader br = new BufferedReader(new InputStreamReader(System.in));
        String line1 = br.readLine().trim();
        String line2 = br.readLine().trim();
        String line3 = br.readLine().trim();

        int[][] blocked = parseArray2D(line1);
        int[] source = parseArray1D(line2);
        int[] target = parseArray1D(line3);

        System.out.println(solution(blocked, source, target));
    }

    private static int[][] parseArray2D(String s) {
        s = s.substring(1, s.length()-1);
        if (s.isEmpty()) return new int[0][];
        String[] parts = s.split("],\\[");
        int[][] result = new int[parts.length][];
        for (int i = 0; i < parts.length; i++) {
            String part = parts[i].replaceAll("\\[|\\]", "");
            String[] nums = part.split(",");
            result[i] = new int[nums.length];
            for (int j = 0; j < nums.length; j++) {
                result[i][j] = Integer.parseInt(nums[j]);
            }
        }
        return result;
    }

    private static int[] parseArray1D(String s) {
        s = s.substring(1, s.length()-1);
        String[] parts = s.split(",");
        int[] result = new int[parts.length];
        for (int i = 0; i < parts.length; i++) {
            result[i] = Integer.parseInt(parts[i]);
        }
        return result;
    }
