    if blocked[startKey] {
        return false
    }

    queue := [][]int{start}
    visited := make(map[string]bool)
    visited[startKey] = true
    directions := [][]int{{0, 1}, {1, 0}, {0, -1}, {-1, 0}}

    for len(queue) > 0 && len(visited) <= maxArea {
        curr := queue[0]
        queue = queue[1:]

        if curr[0] == end[0] && curr[1] == end[1] {
            return true
        }

        for _, dir := range directions {
            nx, ny := curr[0]+dir[0], curr[1]+dir[1]
            key := strconv.Itoa(nx) + "," + strconv.Itoa(ny)

            if nx >= 0 && nx < 1000000 && ny >= 0 && ny < 1000000 {
                if !blocked[key] && !visited[key] {
                    visited[key] = true
                    queue = append(queue, []int{nx, ny})
                }
            }
        }
    }

    return len(visited) > maxArea
